var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라, 잠깐 나와 봐. 손님이야.","JPN":"ラウラ、ちょっと来て。お客さんだわ。","ENG":"Laura, come on out here for a second. We've got a customer.","TWN":"蘿拉，妳出來一下，有客人。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"마감 시간에 웬 손님이람. 커피 한 잔 주고 돌려보내.","JPN":"閉店時間に客だと？　コーヒー一杯渡して送り返せ。","ENG":"But it's nearly closing time. Just give them a cup of coffee on the house and kick them out.","TWN":"都到要下班了怎麼還有客人。給杯咖啡打發他回去吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아쉽지만 다른 용건이야.","JPN":"残念だけど、コーヒーを飲みに来たんじゃないわ。","ENG":"Unfortunately she's here for another reason.","TWN":"很可惜，是有別的事情。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"전단지 돌리는 마녀에게 여기 오면 소원을 이뤄 준다는 얘기를 들었다던데?","JPN":"チラシを配っていた魔女に、ここに来ると願い事を叶えてくれるって聞いたそうよ。","ENG":"She said a witch gave her a pamphlet saying we can grant her wish here.","TWN":"她說發傳單的魔女告訴她，只要來到店裡就能實現願望？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......또 그 바보 소행이구나. 정말 지치지도 않나 보네.","JPN":"……またあのバカの仕業か。あいつも懲りないものだ。","ENG":"Ugh, it's that idiot again... She never gives up, does she?","TWN":"……又是那個笨蛋做的好事啊，她真是不會膩耶。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 아까 그 사람! 바로 와 줬어! 아자! 마케팅의 성공!","JPN":"あっ！　さっきの人ね！　すぐに来てくれたんだ！　やった！　客引き成功！","ENG":"Oh! It's her from before! She really came! Woohoo! My marketing worked!","TWN":"啊！剛才那個人！這麼快就來啦！耶！推銷成功！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"플루토. 마구 할퀴어 버려.","JPN":"プルートー。引っ掻いてやれ。","ENG":"Pluto. Tear up her face.","TWN":"布魯托，抓爛她的臉。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아야야야! 미안, 플루토! 정어리 사 줄게! 정어리!","JPN":"あいたたた！　ごめん、プルートー！　イワシ買ってあげるから！　イワシ！","ENG":"Ow! I'm sorry, Pluto! I'll buy you a can of tuna! Tuna!","TWN":"啊啊啊啊！抱歉，布魯托！我會給你買沙丁魚的！沙丁魚！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"야박하게 왜 그래. 지점 낸 뒤로 기념할 만한 첫 손님이잖아.","JPN":"薄情なことしないで。支店を出してからの、記念すべき初めてのお客さんでしょ。","ENG":"Don't be so hard on her. It's our first customer after opening this branch.","TWN":"不要這麼無情嘛，這可是分店開張後值得紀念的第一位客人耶。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"정말 여기서 내 소원을 이뤄 줄 수 있어?","JPN":"本当にここで私の願い事を叶えてもらえるの？","ENG":"Can you guys really grant my wish here?","TWN":"這裡真的可以實現我的願望嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......그래. 같은 카운터 능력이라도 어떻게 쓰느냐에 따라 할 수 있는 일이 다르거든.","JPN":"……そうだ。同じカウンターでも能力をどう使うかによって、できることが違うからな。","ENG":"Yeah. There's all sorts of ways Counters can use their abilities.","TWN":"……沒錯。但就算是同樣的制裁者能力，也會因不同的使用方法獲得不同的結果。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"물론 마녀에게 소원을 빌려면 대가가 필요해.","JPN":"もちろん、魔女に願い事をするためには対価が必要だ。","ENG":"Of course, you'll have to pay a price if you want a witch to grant you your wish.","TWN":"當然，向魔女許願是需要代價的。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그리고 난 네가 뭘 주든 절대 안 받을 거야. 메롱.","JPN":"それに妾は汝に何を渡されようが、絶対受け取らない。ベーだ。","ENG":"And I won't take any payment from you, no matter what. So get lost.","TWN":"還有，無論妳給我什麼我都不會收下的。吐舌頭～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"심술 궂어. 마귀 할멈.","JPN":"意地悪の鬼婆ね。","ENG":"You're mean. A mean old witch.","TWN":"壞心眼，老巫婆。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그러는 넌 급체 걸린 백설공주니?","JPN":"そういう汝こそ、急に胃もたれでもした白雪姫か？","ENG":"Think that makes you Snow White or something?","TWN":"那妳就是消化不良的白雪公主囉？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아, 어디서 봤나 했더니 하트베리였구나?","JPN":"あ、見覚えがあると思ったらハートベリーの子よね？","ENG":"Oh, I knew I've seen you from somewhere! You're HRT Berry, right?","TWN":"啊，我說怎麼這麼眼熟，這不是愛心莓果嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"가은이 맞지? 얼음공주!","JPN":"ユキでしょ？　氷姫の！","ENG":"Gaeun, right? The Icy Princess!","TWN":"嘉恩對吧？冰雪公主！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};